mapper.select:
SELECT s.id AS id, s.name AS name, sp.name AS positionName, lt.type_num as typeNum FROM course c -- 直接关联课程配置表，这里的 lesson_id 实际存储的是 course_id JOIN lesson_teacher lt ON c.id = lt.lesson_id -- 关联老师表 JOIN staff s ON lt.teacher_id = s.id and s.deleted = 0 -- 关联组织信息表 JOIN staff_orginfo soi ON s.id = soi.staff_id AND soi.deleted = 0 -- 关联职位表 JOIN staff_position sp ON soi.position_id = sp.id
c.deleted = 0
and c.id = #{query.courseId}
AND s.name LIKE CONCAT('%', #{query.teacherName}, '%')
and lt.type_num = #{query.type}
order by s.name asc,s.id
